               \"ambito\": null,\n                \"tipo\": \"comunicacion_oral\",\n                \"id_evento\": \"evento_102\",\n                \"fuente_texto\": \"Influencia de la Inteligencia Artificial en la comunicación en la salud\",\n                \"confianza_extraccion\": 0.6,\n                \"requiere_revision\": true\n            },\n            {\n                \"id\": \"cong_103\",\n                \"es_valido\": true,\n                \"ambito\": null,\n                \"tipo\": \"comunicacion_oral\",\n                \"id_evento\": \"evento_103\",\n                \"fuente_texto\": \"Cátedra de Comunicación y Salud (UCM-AbbVie); Real Colegio\",\n                \"confianza_extraccion\": 0.6,\n                \"requiere_revision\": true\n            }\n        ],\n        \"otros_meritos_investigacion\": [\n            {\n                \"id\": \"omi_001\",\n                \"es_valido\": true,\n                \"tipo\": \"premio\",\n                \"fuente_texto\": \"premio\",\n                \"confianza_extraccion\": 0.6,\n                \"requiere_revision\": true\n            },\n            {\n                \"id\": \"omi_002\",\n                \"es_valido\": true,\n                \"tipo\": \"grupo_investigacion\",\n                \"fuente_texto\": \"grupo de investigación\",\n                \"confianza_extraccion\": 0.6,\n                \"requiere_revision\": true\n            }\n        ]\n    },\n    \"bloque_2\": {\n        \"docencia_universitaria\": [],\n        \"evaluacion_docente\": [\n            {\n                \"id\": \"eval_001\",\n                \"es_valido\": true,\n                \"tipo\": \"encuestas\",\n                \"resultado\": \"positiva\",\n                \"fuente_texto\": \"encuestas\\/evaluación docente\",\n                \"confianza_extraccion\": 0.65,\n                \"requiere_revision\": true\n            }\n        ],\n        \"formacion_docente\": [],\n        \"material_docente\": [\n            {\n                \"id\": \"mat_001\",\n                \"es_valido\": true,\n                \"tipo\": \"material_publicado\",\n                \"fuente_texto\": \"material publicado\",\n                \"confianza_extraccion\": 0.6,\n                \"requiere_revision\": true\n            },\n            {\n                \"id\": \"mat_002\",\n                \"es_valido\": true,\n                \"tipo\": \"proyecto_innovacion\",\n                \"fuente_texto\": \"proyecto de innovación docente\",\n                \"confianza_extraccion\": 0.75,\n                \"requiere_revision\": false\n            }\n        ]\n    },\n    \"bloque_3\": {\n        \"formacion_academica\": [\n            {\n                \"id\": \"form_001\",\n                \"es_valido\": true,\n                \"tipo\": \"master\",\n                \"fuente_texto\": \"máster\",\n                \"confianza_extraccion\": 0.7,\n                \"requiere_revision\": true\n            }\n        ],\n        \"experiencia_profesional\": [\n            {\n                \"id\": \"exp_001\",\n                \"es_valido\": true,\n                \"anios\": 25,\n                \"relacion\": \"alta\",\n                \"fuente_texto\": \"25 años en multinacionales, empresa\",\n                \"confianza_extraccion\": 0.7,\n                \"requiere_revision\": false\n            }\n        ]\n    },\n    \"bloque_4\": [\n        {\n            \"id\": \"b4_001\",\n            \"es_valido\": true,\n            \"tipo\": \"gestion\",\n            \"fuente_texto\": \"gestión\",\n            \"confianza_extraccion\": 0.6,\n            \"requiere_revision\": true\n        },\n        {\n            \"id\": \"b4_002\",\n            \"es_valido\": true,\n            \"tipo\": \"distincion\",\n            \"fuente_texto\": \"reconocimiento\",\n            \"confianza_extraccion\": 0.6,\n            \"requiere_revision\": true\n        }\n    ],\n    \"metadatos_extraccion\": {\n        \"comite\": \"CSYJ\",\n        \"subcomite\": null,\n        \"archivo_pdf\": null,\n        \"fecha_extraccion\": \"2026-04-07T10:23:41+02:00\",\n        \"version_esquema\": \"1.0\",\n        \"requiere_revision_manual\": true\n    },\n    \"archivo_pdf\": \"exp_69d4bf0cb536f.pdf\",\n    \"json_generado\": \"exp_69d4bf0cb536f.json\",\n    \"texto_extraido\": \"CURRICULUM\\nDATOS PERSONALES\\nAPELLIDO1\\nAPELLIDO2\\nNOMBRE\\nFNACIMIENTO\\nSEXO\\nNACIONALIDAD\\nTIPO DOCUMENTO\\nDOCUMENTO TIPO\\nDOCUMENTO\\nPAIS DIRECCION\\nDIRECCION1\\nDIRECCION2\\nCIUDAD\\nCPOSTAL\\nPROVINCIA\\nAUTONOMIA\\nTELEFONO\\nTELEFONO MOVIL\\nFAX\\nCORREO ELECTRONICO\\n\\nCARVAJAL\\nZAERA\\nENRIQUE SALVADOR\\n1972-01-07\\nV\\nE\\n01001\\n27313910F\\nE\\nC\\/ HISPANO AVIACIÓN, 6. BLOQUE 4, 3ºD\\nSEVILLA\\n41011\\nSEVILLA\\nCOMUNIDAD AUTÓNOMA DE ANDALUCÍA\\n639366276\\n\\nenriquecarvajalzaera@gmail.com\\n\\nAUTOEVALUACION\\nSoy licenciado en Ciencias Económicas y Empresariales por la US (1997). Asimismo,\\nobtuve el doctorado en el Programa de Doctorado en Comunicación Audiovisual,\\nPublicidad y Relaciones Públicas (2015) con la tesis La fidelidad del consumidor\\nen la distribución detallista, dirigida por J. L. Galán González y M. Domínguez de\\nla Concha-Castañeda. Complementariamente, cuento con formación de posgrado:\\nMBA en el Instituto de Empresa (1999), Global Senior Management Program en\\nUniversity of Chicago GSB (2006) y Máster Universitario en Estudios Europeos (2013).\\nInicié mi labor docente en el año 2007 en escuelas de negocio acumulando 7.145\\nh. He impartido docencia en 6 universidades #US, CEU, UF3, UPO, UEM, UHU y\\nUniversidad Nebrija# y, además, en centros\\/escuelas de negocio como Instituto de\\nEmpresa, EOI, ESIC, EAE Business School, Instituto de Estudios Cajasol y Cámara de\\nComercio de Sevilla. Mis asignaturas se han concentrado en áreas como marketing,\\nmarketing digital, investigación de mercados, planificación y gestión de medios,\\nestrategia y gestión empresarial, emprendimiento y transformación digital, entre otras.\\nHe impartido 4.293 h en Grado y 2.852 h en Máster\\/Posgrado, combinando docencia\\npresencial con docencia en programas online (aprox. 913 h). Además, he ofrecido\\n300 h en inglés en materias específicas (Tourism Marketing y Market research for\\ntourism). Además de la formación no reglada en las diferentes escuelas de negocios.\\nParalelamente, he participado como IP en 1 proyecto de innovación docente, centrado\\n\\n1\\n\\n\\fen la realización de planes de marketing con empresas reales dentro de la asignatura\\nPlan de Marketing (2021#23). Asimismo, he dirigido 3 TFM y 2 TFG, fomentando\\nel desarrollo de investigaciones aplicadas y sólidas. Las encuestas de evaluación\\ndocente registradas reflejan calificaciones altas, con una valoración media de 8,47\\/10.\\nEn el ámbito investigador, he publicado 6 artículos en revistas con índice de impacto\\ny 6 capítulos\\/libros. He asistido a 6 congresos, destacando CUICIID (2024), CICS\\n(2024) y COMRED (2025), además de labores de organización en COMUSOC (2025).\\nEn relación con proyectos de investigación, participo en 2: #Eficiencia, tecnología,\\ndignidad y derechos humanos ¿Quo vadis, humanidad, en la era de la IA?# y en\\n#La Securitización de la lucha contra la inmigración irregular en el Mediterráneo por\\nparte de la UE y España: Un enfoque multidisciplinar#. Por otro lado, participo en\\ndos grupos de investigación (UF3RISD e IMPACTA). Asimismo, he dirigido más de\\n20 proyectos de transmisión del conocimiento desarrollados con distintos tipos de\\norganizaciones y en diversos sectores. A ello se suma, finalmente, una experiencia\\nprofesional contrastada de más de 25 años en multinacionales, empresas privadas y\\ncomo empresario emprendedor.\\n\\nEXPERIENCIA INVESTIGADORA\\nPUBLICACIONES CIENTIFICAS\\nTítulo\\n\\nAño\\n\\nEstudio de los métodos de fidelización Análisis y comparativa de métodos en 2015\\nEspaña\\nValor, satisfacción y fide